+function drawThrone(ctx: CanvasRenderingContext2D, x: number, y: number, s: number) {
+  // Ornate gold throne with red cushion, 28x32 px approx, detailed pixel art with wood grain, metal studs, fabric texture, and shadows
+  ctx.save();
+  ctx.translate(x, y);
+  ctx.scale(s, s);
+
+  // Backrest frame with wood grain texture
+  ctx.fillStyle = '#d4af37';
+  ctx.fillRect(4, 0, 20, 28);
+  ctx.strokeStyle = '#a67c00';
+  ctx.lineWidth = 1;
+  // Metal studs (small circles)
+  for (let i = 6; i < 24; i += 4) {
+    ctx.beginPath();
+    ctx.arc(i, 4, 1, 0, Math.PI * 2);
+    ctx.fillStyle = '#bfa03e';
+    ctx.fill();
+    ctx.strokeStyle = '#8a6f1a';
+    ctx.stroke();
+  }
+  // Wood grain lines
+  ctx.strokeStyle = '#a67c00';
+  ctx.lineWidth = 1;
+  for (let i = 5; i < 24; i += 4) {
+    ctx.beginPath();
+    ctx.moveTo(i, 8);
+    ctx.lineTo(i - 2, 18);
+    ctx.stroke();
+  }
+
+  // Cushion (red velvet with fabric texture and shading)
+  const cushionGradient = ctx.createLinearGradient(6, 18, 22, 28);
+  cushionGradient.addColorStop(0, '#a32a2a');
+  cushionGradient.addColorStop(1, '#7a1a1a');
+  ctx.fillStyle = cushionGradient;
+  ctx.fillRect(6, 18, 16, 10);
+  // Fabric folds (thin lines)
+  ctx.strokeStyle = '#7a1a1a';
+  ctx.lineWidth = 0.5;
+  for (let i = 7; i < 22; i += 3) {
+    ctx.beginPath();
+    ctx.moveTo(i, 18);
+    ctx.lineTo(i - 2, 27);
+    ctx.stroke();
+  }
+
+  // Decorative top arch with gradient fill and shadow
+  const grad = ctx.createLinearGradient(4, 0, 24, 0);
+  grad.addColorStop(0, '#d4af37');
+  grad.addColorStop(0.5, '#f0d75e');
+  grad.addColorStop(1, '#d4af37');
+  ctx.fillStyle = grad;
+  ctx.beginPath();
+  ctx.moveTo(4, 0);
+  ctx.bezierCurveTo(14, -12, 24, 0, 24, 0);
+  ctx.lineTo(4, 0);
+  ctx.fill();
+  // Shadow under arch
+  ctx.fillStyle = 'rgba(0,0,0,0.15)';
+  ctx.beginPath();
+  ctx.moveTo(4, 0);
+  ctx.bezierCurveTo(14, -10, 24, 0, 24, 0);
+  ctx.lineTo(4, 0);
+  ctx.fill();
+
+  // Legs with shadows and highlights and wood grain
+  ctx.fillStyle = '#bfa03e';
+  ctx.fillRect(4, 28, 6, 4);
+  ctx.fillRect(18, 28, 6, 4);
+  ctx.strokeStyle = '#8a6f1a';
+  ctx.lineWidth = 1;
+  ctx.strokeRect(4, 28, 6, 4);
+  ctx.strokeRect(18, 28, 6, 4);
+  // Wood grain on legs
+  ctx.strokeStyle = '#a67c00';
+  ctx.lineWidth = 0.5;
+  for (let i = 5; i < 9; i += 2) {
+    ctx.beginPath();
+    ctx.moveTo(4 + i, 28);
+    ctx.lineTo(4 + i - 1, 32);
+    ctx.stroke();
+    ctx.beginPath();
+    ctx.moveTo(18 + i, 28);
+    ctx.lineTo(18 + i - 1, 32);
+    ctx.stroke();
+  }
+  ctx.restore();
+}
