+function drawWorkbench(ctx: CanvasRenderingContext2D, x: number, y: number, s: number) {
+  // Workbench with detailed tools, wood grain, metal highlights, shadows, 32x24 px approx
+  ctx.save();
+  ctx.translate(x, y);
+  ctx.scale(s, s);
+
+  // Bench top with wood grain texture
+  ctx.fillStyle = '#7a5230';
+  ctx.fillRect(0, 8, 32, 12);
+  ctx.strokeStyle = '#6a4320';
+  ctx.lineWidth = 1;
+  for (let i = 2; i < 30; i += 3) {
+    ctx.beginPath();
+    ctx.moveTo(i, 10);
+    ctx.lineTo(i + 1, 18);
+    ctx.stroke();
+  }
+  // Additional wood grain lines
+  ctx.strokeStyle = '#5a3f21';
+  ctx.lineWidth = 0.5;
+  for (let i = 4; i < 30; i += 4) {
+    ctx.beginPath();
+    ctx.moveTo(i, 9);
+    ctx.lineTo(i - 2, 18);
+    ctx.stroke();
+  }
+
+  // Legs with shading and wood grain
+  ctx.fillStyle = '#5a3f21';
+  ctx.fillRect(2, 20, 6, 4);
+  ctx.fillRect(24, 20, 6, 4);
+  ctx.strokeStyle = '#4a2f1a';
+  ctx.lineWidth = 1;
+  ctx.strokeRect(2, 20, 6, 4);
+  ctx.strokeRect(24, 20, 6, 4);
+  ctx.strokeStyle = '#6a4320';
+  ctx.lineWidth = 0.5;
+  for (let i = 3; i < 8; i += 2) {
+    ctx.beginPath();
+    ctx.moveTo(2 + i, 20);
+    ctx.lineTo(2 + i - 1, 24);
+    ctx.stroke();
+    ctx.beginPath();
+    ctx.moveTo(24 + i, 20);
+    ctx.lineTo(24 + i - 1, 24);
+    ctx.stroke();
+  }
+
+  // Hammer (handle + head) with metal texture and highlights
+  ctx.strokeStyle = '#3a2f2a';
+  ctx.lineWidth = 2;
+  ctx.beginPath();
+  ctx.moveTo(8, 14);
+  ctx.lineTo(8, 18);
+  ctx.moveTo(6, 18);
+  ctx.lineTo(10, 18);
+  ctx.stroke();
+  ctx.fillStyle = '#5a4a40';
+  ctx.fillRect(5, 13, 6, 2);
+  // Hammer head highlights
+  ctx.strokeStyle = '#7a6a5a';
+  ctx.lineWidth = 1;
+  ctx.strokeRect(5, 13, 6, 2);
+
+  // Saw blade (gray jagged with teeth and shadows)
+  ctx.fillStyle = '#a0a0a0';
+  ctx.beginPath();
+  ctx.moveTo(20, 14);
+  for (let i = 0; i < 5; i++) {
+    ctx.lineTo(20 + i * 2, 14 + (i % 2 === 0 ? 4 : 0));
+  }
+  ctx.lineTo(30, 18);
+  ctx.closePath();
+  ctx.fill();
+  // Saw teeth highlights
+  ctx.strokeStyle = '#7a7a7a';
+  ctx.lineWidth = 1;
+  ctx.beginPath();
+  for (let i = 0; i < 5; i++) {
+    ctx.moveTo(20 + i * 2, 14);
+    ctx.lineTo(20 + i * 2, 18);
+  }
+  ctx.stroke();
+  // Saw blade shadow
+  ctx.strokeStyle = 'rgba(0,0,0,0.15)';
+  ctx.lineWidth = 1;
+  ctx.beginPath();
+  ctx.moveTo(20, 18);
+  for (let i = 0; i < 5; i++) {
+    ctx.lineTo(20 + i * 2, 18 + (i % 2 === 0 ? 2 : 0));
+  }
+  ctx.stroke();
+
+  ctx.restore();
+}
