+function drawScribeDesk(ctx: CanvasRenderingContext2D, x: number, y: number, s: number) {
+  // Desk with quill and book, 30x24 px approx, detailed pixel art with wood grain, fabric, ink pot shine, shadows
+  ctx.save();
+  ctx.translate(x, y);
+  ctx.scale(s, s);
+
+  // Desk top with wood grain texture
+  ctx.fillStyle = '#5a3f21';
+  ctx.fillRect(0, 8, 30, 12);
+  ctx.strokeStyle = '#4a2f10';
+  ctx.lineWidth = 1;
+  for (let i = 2; i < 28; i += 3) {
+    ctx.beginPath();
+    ctx.moveTo(i, 10);
+    ctx.lineTo(i + 1, 18);
+    ctx.stroke();
+  }
+  // Additional wood grain lines
+  ctx.strokeStyle = '#3a2f10';
+  ctx.lineWidth = 0.5;
+  for (let i = 4; i < 28; i += 5) {
+    ctx.beginPath();
+    ctx.moveTo(i, 9);
+    ctx.lineTo(i - 2, 18);
+    ctx.stroke();
+  }
+
+  // Legs with shading and wood grain
+  ctx.fillStyle = '#4a2f10';
+  ctx.fillRect(2, 20, 6, 4);
+  ctx.fillRect(22, 20, 6, 4);
+  ctx.strokeRect(2, 20, 6, 4);
+  ctx.strokeRect(22, 20, 6, 4);
+  ctx.strokeStyle = '#3a2010';
+  ctx.lineWidth = 0.5;
+  for (let i = 3; i < 8; i += 2) {
+    ctx.beginPath();
+    ctx.moveTo(2 + i, 20);
+    ctx.lineTo(2 + i - 1, 24);
+    ctx.stroke();
+    ctx.beginPath();
+    ctx.moveTo(22 + i, 20);
+    ctx.lineTo(22 + i - 1, 24);
+    ctx.stroke();
+  }
+
+  // Open book (cream pages with lines and shadow)
+  ctx.fillStyle = '#f9f4d7';
+  ctx.fillRect(6, 10, 18, 8);
+  ctx.strokeStyle = '#d9d1a3';
+  ctx.lineWidth = 1;
+  ctx.strokeRect(6, 10, 18, 8);
+  ctx.strokeStyle = '#a3a375';
+  for (let yline = 12; yline < 17; yline += 2) {
+    ctx.beginPath();
+    ctx.moveTo(7, yline);
+    ctx.lineTo(23, yline);
+    ctx.stroke();
+  }
+  // Book shadow
+  ctx.fillStyle = 'rgba(0,0,0,0.1)';
+  ctx.fillRect(6, 17, 18, 2);
+
+  // Quill (white feather with black tip and shading)
+  ctx.strokeStyle = '#222';
+  ctx.lineWidth = 1;
+  ctx.fillStyle = '#eee';
+  ctx.beginPath();
+  ctx.moveTo(24, 12);
+  ctx.lineTo(28, 8);
+  ctx.lineTo(26, 6);
+  ctx.lineTo(22, 10);
+  ctx.closePath();
+  ctx.fill();
+  ctx.stroke();
+  ctx.fillStyle = '#111';
+  ctx.beginPath();
