+function drawFurniture(ctx: CanvasRenderingContext2D, roomType: string, x: number, y: number, scale: number) {
+  switch(roomType) {
+    case 'throneRoom':
+      drawThrone(ctx, x + 10 * scale, y + 4 * scale, scale);
+      drawPlanningTable(ctx, x + 50 * scale, y + 12 * scale, scale);
+      break;
+    case 'armory':
+      drawWeaponRack(ctx, x + 8 * scale, y + 8 * scale, scale);
+      drawWorkbench(ctx, x + 48 * scale, y + 12 * scale, scale);
+      break;
+    case 'alchemyLab':
+      drawPotionShelf(ctx, x + 12 * scale, y + 6 * scale, scale);
+      drawScribeDesk(ctx, x + 52 * scale, y + 14 * scale, scale);
+      break;
+    case 'workshop':
+      drawWorkbench(ctx, x + 10 * scale, y + 10 * scale, scale);
+      break;
+    case 'scribeDesk':
+      drawScribeDesk(ctx, x + 10 * scale, y + 10 * scale, scale);
+      break;
+    case 'healingBasin':
+      drawHealingBasin(ctx, x + 10 * scale, y + 10 * scale, scale);
+      break;
+  }
+}
